/**
 * Unified Cross-Country Panel Dataset
 *
 * One row per country-year, combining income, health, spending, and demographic
 * indicators from World Bank, IMF, WHO, OECD, and Eurostat.
 *
 * Designed for the Optimitron optimizer to identify optimal budgets and policies
 * that maximize median income and healthy life expectancy.
 *
 * Generated by: scripts/generate-country-panel.ts
 * Refresh with: pnpm --filter @optimitron/data run generate:country-panel
 */

export interface CountryPanelRow {
  /** ISO 3166-1 alpha-3 country code */
  jurisdictionIso3: string;
  /** Human-readable country name */
  jurisdictionName: string;
  /** Calendar year */
  year: number;

  // === TARGET METRICS ===

  /** After-tax median income per capita, PPP (best available source) */
  afterTaxMedianIncomePerCapitaPpp: number | null;
  /** Source of the after-tax median income value */
  afterTaxMedianIncomeSource: string | null;
  /** Whether the income value is from a survey or derived */
  afterTaxMedianIncomeIsAfterTax: boolean;
  /** Pre-tax median income per capita, PPP (World Bank PIP) */
  medianIncomePerCapitaPpp: number | null;
  /** GDP per capita, PPP current international $ (World Bank) */
  gdpPerCapitaPpp: number | null;

  /** Healthy life expectancy at birth, years (WHO HALE) */
  haleYears: number | null;
  /** Life expectancy at birth, total years (World Bank) */
  lifeExpectancyYears: number | null;
  /** Infant mortality per 1,000 live births (World Bank) */
  infantMortalityPer1000: number | null;

  // === GOVERNMENT SPENDING (predictors) — % of GDP ===

  /** General government total expenditure, all levels (IMF Fiscal Monitor) */
  totalGovSpendingPctGdp: number | null;
  /** Current health expenditure (World Bank) */
  healthSpendingPctGdp: number | null;
  /** Government education expenditure (World Bank) */
  educationSpendingPctGdp: number | null;
  /** Military expenditure (World Bank) */
  militarySpendingPctGdp: number | null;
  /** R&D expenditure (World Bank) */
  rdSpendingPctGdp: number | null;

  // === GOVERNMENT SPENDING — per capita PPP (derived) ===

  /** Total gov spending per capita PPP (totalGovSpendingPctGdp × gdpPerCapitaPpp / 100) */
  totalGovSpendingPerCapitaPpp: number | null;
  /** Health spending per capita PPP */
  healthSpendingPerCapitaPpp: number | null;
  /** Education spending per capita PPP */
  educationSpendingPerCapitaPpp: number | null;
  /** Military spending per capita PPP */
  militarySpendingPerCapitaPpp: number | null;
  /** R&D spending per capita PPP */
  rdSpendingPerCapitaPpp: number | null;

  // === INEQUALITY & WELFARE ===

  /** Gini index (0 = equal, 100 = max inequality) */
  giniIndex: number | null;
  /** Poverty rate at $2.15/day (2017 PPP) */
  povertyRate: number | null;

  // === DEMOGRAPHICS ===

  /** Total population */
  population: number | null;
}

export interface CountryPanelMetadata {
  generatedAt: string;
  rowCount: number;
  countryCount: number;
  yearRange: [number, number];
  sources: string[];
}

// These are populated by the generated module
export let COUNTRY_PANEL: CountryPanelRow[] = [];
export let COUNTRY_PANEL_METADATA: CountryPanelMetadata | null = null;

/**
 * Initialize from generated data (called by generated module).
 */
export function setCountryPanel(
  rows: CountryPanelRow[],
  metadata: CountryPanelMetadata,
): void {
  COUNTRY_PANEL = rows;
  COUNTRY_PANEL_METADATA = metadata;
}

/** Get all rows */
export function getCountryPanel(): CountryPanelRow[] {
  return COUNTRY_PANEL;
}

/** Get rows for a specific country */
export function getCountryPanelByCountry(
  iso3: string,
): CountryPanelRow[] {
  return COUNTRY_PANEL.filter((r) => r.jurisdictionIso3 === iso3);
}

/** Get the most recent row per country */
export function getCountryPanelLatest(): CountryPanelRow[] {
  const latest = new Map<string, CountryPanelRow>();
  for (const row of COUNTRY_PANEL) {
    const existing = latest.get(row.jurisdictionIso3);
    if (!existing || row.year > existing.year) {
      latest.set(row.jurisdictionIso3, row);
    }
  }
  return [...latest.values()].sort((a, b) =>
    a.jurisdictionIso3.localeCompare(b.jurisdictionIso3),
  );
}

/** Get rows for a specific year */
export function getCountryPanelByYear(year: number): CountryPanelRow[] {
  return COUNTRY_PANEL.filter((r) => r.year === year);
}
